<script setup lang="ts">import{computed}from'vue';import{useQuery}from'@tanstack/vue-query';import{Box,GitBranch,PlayCircle,RefreshCw,ShieldCheck,Tag}from'lucide-vue-next';import Button from'@/components/ui/Button.vue';import StatusBadge from'@/components/ui/StatusBadge.vue';import{getGitHubOverview}from'@/lib/api_github';const query=useQuery({queryKey:['github-overview'],queryFn:getGitHubOverview,refetchInterval:30000});const projects=computed(()=>query.data.value?.projects??[]);const runs=computed(()=>projects.value.flatMap(p=>p.workflow_runs.map(r=>({...r,repo:p.repository.full_name}))));const releases=computed(()=>projects.value.flatMap(p=>p.releases.map(r=>({...r,repo:p.repository.full_name}))));const active=computed(()=>runs.value.filter(r=>r.status!=='completed').length);const tone=(status:string,conclusion:string)=>status!=='completed'?'info':conclusion==='success'?'healthy':conclusion==='failure'?'critical':'warning';</script>
<template><div class="mx-auto max-w-[1680px] space-y-5"><header class="flex flex-col justify-between gap-4 md:flex-row md:items-end"><div><div class="flex gap-2"><StatusBadge status="healthy" label="allowlisted repositories"/><span class="inline-flex items-center gap-1.5 font-mono text-[10px] uppercase text-signal"><ShieldCheck class="h-3.5 w-3.5"/>fine-grained read-only</span></div><h1 class="mt-4 text-3xl font-semibold">GitHub delivery</h1><p class="mt-2 text-sm text-muted">Repositórios autorizados, execuções de Actions e releases publicadas.</p></div><Button variant="outline" :disabled="query.isFetching.value" @click="query.refetch()"><RefreshCw :class="['h-4 w-4',query.isFetching.value&&'animate-spin']"/>Atualizar</Button></header><div v-if="query.isError.value" class="rounded-xl border border-danger/20 bg-danger/5 p-4 text-sm text-danger">GitHub indisponível. Verifique o token fine-grained e a allowlist explícita.</div><section class="grid gap-3 sm:grid-cols-3"><article v-for="item in [{l:'Repositories',v:projects.length,i:Box},{l:'Active workflows',v:active,i:PlayCircle},{l:'Recent releases',v:releases.length,i:Tag}]" :key="item.l" class="rounded-xl border border-line bg-panel/65 p-5"><component :is="item.i" class="h-4 w-4 text-muted"/><p class="mt-5 font-mono text-2xl">{{item.v}}</p><p class="text-xs text-muted">{{item.l}}</p></article></section><section class="grid gap-5 xl:grid-cols-[1.2fr_.8fr]"><article class="overflow-hidden rounded-xl border border-line bg-panel/65"><header class="border-b border-line p-4"><h2 class="text-sm font-medium">CI/CD workflow runs</h2></header><div class="divide-y divide-line/60"><div v-for="run in runs.slice(0,40)" :key="run.id" class="grid gap-3 p-4 md:grid-cols-[1fr_140px_120px] md:items-center"><div class="flex gap-3"><GitBranch class="mt-0.5 h-4 w-4 text-pulse"/><div><p class="text-sm text-slate-200">{{run.display_title||run.name}}</p><p class="mt-1 font-mono text-[9px] text-muted">{{run.repo}} · {{run.head_branch}} · #{{run.run_number}}</p></div></div><StatusBadge :status="tone(run.status,run.conclusion)" :label="run.conclusion||run.status"/><p class="text-xs text-muted md:text-right">{{new Date(run.updated_at).toLocaleString('pt-BR')}}</p></div><p v-if="!runs.length" class="p-10 text-center text-sm text-muted">Nenhum workflow encontrado.</p></div></article><aside class="rounded-xl border border-line bg-panel/55"><header class="border-b border-line p-4"><h2 class="text-sm font-medium">Releases</h2></header><div class="divide-y divide-line/60"><a v-for="release in releases.slice(0,25)" :key="release.id" :href="release.html_url" target="_blank" rel="noreferrer" class="block p-4 hover:bg-white/[.02]"><div class="flex items-center gap-2"><Tag class="h-3.5 w-3.5 text-signal"/><p class="text-sm text-slate-200">{{release.name||release.tag_name}}</p></div><p class="mt-2 font-mono text-[9px] text-muted">{{release.repo}} · {{release.tag_name}}</p></a><p v-if="!releases.length" class="p-8 text-center text-xs text-muted">Nenhuma release publicada.</p></div></aside></section></div></template>
